mapper.select:
SELECT EXISTS (
    SELECT 1 FROM post_subscription
     WHERE user_id = #{userId} AND post_id = #{postId}
       AND deleted_at IS NULL
)

SELECT EXISTS (
    SELECT 1 FROM comment_subscription
     WHERE user_id = #{userId} AND comment_id = #{commentId}
       AND deleted_at IS NULL
)

SELECT cs.comment_id
  FROM comment_subscription cs
  JOIN community_comment cc ON cc.id = cs.comment_id
 WHERE cs.user_id = #{userId}
   AND cs.deleted_at IS NULL
   AND cc.post_id = #{postId}
